#include<bits/stdc++.h>
using namespace std;
const int N=200010;
int f[N],g[N],ans,n;
vector<pair<int,int>> mp[N];
void dfs(int x,int fa=-1)
{
    f[x]=0;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            dfs(v,x);
            if(mp[v].size()==1)
            {
                f[x]+=val;
            }
            else
            {
                f[x]+=min(f[v],val);
            }
        }
    }
}
void dfs2(int x,int fa=-1)
{
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            if(mp[v].size()==1)
            {
                g[v]=f[v]+val;
            }
            else
            {
                g[v]=f[v]+min(g[x]-min(f[v],val),val);
            }
            dfs2(v,x);
        }
    }
    ans=max(ans,g[x]);
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d",&n);
        for(int i=0;i<=n;i++)
        {
            mp[i].clear();
            f[i]=g[i]=0;
        }
        ans=0;
        for(int i=1;i<n;i++)
        {
            int u,v,w;
            scanf("%d%d%d",&u,&v,&w);
            mp[u].push_back(make_pair(v,w));
            mp[v].push_back(make_pair(u,w));
        }
        dfs(1);
        g[1]=f[1];
        dfs2(1);
        printf("%d\n",ans);
    }
    return 0;
}
